#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>

#define NUM_TASKS 5

typedef struct {
    int task_id;
    int priority;  // Lower number = higher priority
    int execution_time;
    int deadline;
} Task;

Task tasks[NUM_TASKS] = {
    {1, 1, 5, 10},
    {2, 2, 3, 15},
    {3, 3, 8, 20},
    {4, 0, 2, 5},   // Highest priority
    {5, 4, 4, 25}
};

// Compare function for sorting by priority
int compare_priority(const void* a, const void* b) {
    Task* t1 = (Task*)a;
    Task* t2 = (Task*)b;
    return t1->priority - t2->priority;
}

void* execute_task(void* arg) {
    Task* task = (Task*)arg;
    printf("Executing Task %d | Priority: %d | Time: %dms | Deadline: %dms\n",
           task->task_id, task->priority, task->execution_time, task->deadline);
    // Simulate task execution
    usleep(task->execution_time * 1000);
    printf("Task %d completed\n", task->task_id);
    return NULL;
}

int main() {
    pthread_t threads[NUM_TASKS];

    // Sort tasks by priority (simulating RTOS scheduling)
    qsort(tasks, NUM_TASKS, sizeof(Task), compare_priority);

    printf("RTOS Priority-Based Scheduling\n");
    printf("Higher priority tasks execute first\n\n");

    // Create and execute tasks in priority order
    for (int i = 0; i < NUM_TASKS; i++) {
        pthread_create(&threads[i], NULL, execute_task, &tasks[i]);
    }

    // Wait for all tasks to complete
    for (int i = 0; i < NUM_TASKS; i++) {
        pthread_join(threads[i], NULL);
    }

    printf("\nAll real-time tasks completed\n");
    return 0;
}
